// ============================================================
//  KOTAK BANK STATEMENT → EXCEL  |  n8n Code Node
//  ✅ ZERO require() calls — 100% pure JavaScript
//  Works on any locked-down self-hosted n8n instance
// ============================================================

// ── 1. GET OCR TEXT FROM LLMWHISPERER ────────────────────────
const input = $input.item.json;
let fileText = '';
if (Array.isArray(input)) {
  fileText = input[0]?.result_text || '';
} else if (input.result_text) {
  fileText = input.result_text;
} else if (input.ocr_text) {
  fileText = input.ocr_text;
}
fileText = fileText.replace(/\f/g, '\n').trim();
if (!fileText) throw new Error('No OCR text found from LLMWhisperer output.');

// ── 2. PARSE TRANSACTIONS ────────────────────────────────────
const lines = fileText.split('\n');
const transactionsRaw = [];
let currentFirst = null;
let currentCont = [];

for (const line of lines) {
  const stripped = line.replace(/\r$/, '');
  if (/^       \d{2}\/\d{2}\/\d{4}\s+/.test(stripped)) {
    if (currentFirst !== null) transactionsRaw.push([currentFirst, currentCont]);
    currentFirst = stripped;
    currentCont = [];
  } else if (currentFirst !== null && stripped.trim() && /^                    /.test(stripped)) {
    currentCont.push(stripped.trim());
  } else {
    if (currentFirst !== null) {
      transactionsRaw.push([currentFirst, currentCont]);
      currentFirst = null; currentCont = [];
    }
  }
}
if (currentFirst !== null) transactionsRaw.push([currentFirst, currentCont]);

function cleanBeneficiary(name) {
  return name.replace(/\bTransfer\b/g, '').replace(/\s+\d{3,5}$/, '').replace(/\s+/g, ' ').trim();
}

function parseTransaction(firstLine, contLines) {
  const m = firstLine.match(/^\s+(\d{2}\/\d{2}\/\d{4})\s+(.*)/);
  if (!m) return null;
  const dateStr = m[1]; let rest = m[2];

  let status = '';
  const sm = rest.match(/(Success|Failure|Pending)\s*$/i);
  if (sm) { status = sm[1]; rest = rest.slice(0, rest.lastIndexOf(sm[0])).trim(); }

  let amount = 0;
  const am = rest.match(/([\d,]+\.\d{2})\s+INR\s*$/);
  if (am) { amount = parseFloat(am[1].replace(/,/g, '')); rest = rest.slice(0, rest.lastIndexOf(am[0])).trim(); }

  if (/\b4611940519\b/.test(rest)) rest = rest.slice(0, rest.search(/\b4611940519\b/)).trim();

  let txnId = '';
  const tim = rest.match(/(\d{7,12})\s*$/);
  if (tim) { txnId = tim[1]; rest = rest.slice(0, rest.lastIndexOf(tim[0])).trim(); }

  let transferType = '', refId = '', beneficiaryPartial = rest;
  for (const [pattern, ttype] of [
    [/\s+(Third\s+Party\s+Transfer)\s+/i, 'Third Party Transfer'],
    [/\s+(Third\s+Party)\s+/i,            'Third Party Transfer'],
    [/\s+(IMPS)\s+/i,                     'IMPS'],
    [/\s+(Payment)\s+/i,                  'Payment'],
  ]) {
    const mm = rest.match(pattern);
    if (mm) {
      transferType = ttype;
      beneficiaryPartial = rest.slice(0, mm.index).trim();
      refId = rest.slice(mm.index + mm[0].length).trim();
      break;
    }
  }

  const contParts = contLines
    .map(cl => transferType === 'Third Party Transfer' ? cl.replace(/^Transfer\s*/, '').trim() : cl)
    .filter(Boolean);

  let beneficiary = beneficiaryPartial;
  if (contParts.length) beneficiary = (beneficiaryPartial + ' ' + contParts.join(' ')).trim();
  beneficiary = cleanBeneficiary(beneficiary);

  const [dd, mm2, yyyy] = dateStr.split('/');
  const dateObj = new Date(`${yyyy}-${mm2}-${dd}`);
  return { date: dateObj, dateStr, beneficiary, transferType, refId, txnId, debitAccount: '4611940519', amount, status };
}

const transactions = transactionsRaw
  .map(([f, c]) => parseTransaction(f, c))
  .filter(t => t && t.date && !isNaN(t.date));

if (!transactions.length) throw new Error('No transactions parsed. Check OCR output format.');

// ── 3. STATS ─────────────────────────────────────────────────
const totalAmount  = transactions.reduce((s, t) => s + t.amount, 0);
const successCount = transactions.filter(t => t.status === 'Success').length;
const failureCount = transactions.filter(t => t.status === 'Failure').length;
const dates        = transactions.map(t => t.date);
const dateMin      = new Date(Math.min(...dates));
const dateMax      = new Date(Math.max(...dates));
const fmtDate      = d => d.toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });
const fmtNum       = n => n.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

const monthlyMap = {};
for (const t of transactions) {
  const key = `${t.date.getFullYear()}-${String(t.date.getMonth()+1).padStart(2,'0')}`;
  if (!monthlyMap[key]) monthlyMap[key] = { count:0, total:0, success:0 };
  monthlyMap[key].count++; monthlyMap[key].total += t.amount;
  if (t.status === 'Success') monthlyMap[key].success++;
}

const beneMap = {};
for (const t of transactions) {
  if (!beneMap[t.beneficiary]) beneMap[t.beneficiary] = { total:0, count:0 };
  beneMap[t.beneficiary].total += t.amount; beneMap[t.beneficiary].count++;
}
const top10 = Object.entries(beneMap).sort((a, b) => b[1].total - a[1].total).slice(0, 10);

const typeMap = {};
for (const t of transactions) {
  const k = t.transferType || 'Unidentified';
  if (!typeMap[k]) typeMap[k] = { count:0, total:0 };
  typeMap[k].count++; typeMap[k].total += t.amount;
}

// ── 4. PURE JS DEFLATE + ZIP + XLSX ──────────────────────────
// No require() — everything implemented from scratch in pure JS

// ── 4a. String → UTF-8 bytes (as number array) ──
function strToBytes(str) {
  const out = [];
  for (let i = 0; i < str.length; i++) {
    let c = str.charCodeAt(i);
    if (c < 0x80) {
      out.push(c);
    } else if (c < 0x800) {
      out.push(0xC0 | (c >> 6), 0x80 | (c & 0x3F));
    } else if (c >= 0xD800 && c <= 0xDBFF && i+1 < str.length) {
      const c2 = str.charCodeAt(i+1);
      if (c2 >= 0xDC00 && c2 <= 0xDFFF) {
        const cp = 0x10000 + ((c - 0xD800) << 10) + (c2 - 0xDC00);
        out.push(0xF0|(cp>>18), 0x80|((cp>>12)&0x3F), 0x80|((cp>>6)&0x3F), 0x80|(cp&0x3F));
        i++;
      }
    } else {
      out.push(0xE0|(c>>12), 0x80|((c>>6)&0x3F), 0x80|(c&0x3F));
    }
  }
  return out;
}

// ── 4b. CRC-32 ──
const CRC_TABLE = (() => {
  const t = new Array(256);
  for (let i = 0; i < 256; i++) {
    let c = i;
    for (let k = 0; k < 8; k++) c = (c & 1) ? 0xEDB88320 ^ (c >>> 1) : c >>> 1;
    t[i] = c >>> 0;
  }
  return t;
})();

function crc32(bytes) {
  let crc = 0xFFFFFFFF;
  for (let i = 0; i < bytes.length; i++) crc = CRC_TABLE[(crc ^ bytes[i]) & 0xFF] ^ (crc >>> 8);
  return (crc ^ 0xFFFFFFFF) >>> 0;
}

// ── 4c. Deflate (STORE mode — no compression, still valid ZIP/XLSX) ──
// Using STORE (method=0) avoids needing a deflate implementation entirely.
// File size is larger but 100% compatible with Excel.
function deflateStore(bytes) {
  // STORE = no compression. ZIP method 0.
  return { compressed: bytes, method: 0 };
}

// ── 4d. Little-endian helpers (pure arrays) ──
function u16(n) { return [n & 0xFF, (n >> 8) & 0xFF]; }
function u32(n) { n = n >>> 0; return [n & 0xFF, (n>>8)&0xFF, (n>>16)&0xFF, (n>>24)&0xFF]; }

// ── 4e. Build a single ZIP entry ──
function makeZipEntry(filename, contentStr) {
  const nameBytes    = strToBytes(filename);
  const contentBytes = strToBytes(contentStr);
  const { compressed, method } = deflateStore(contentBytes);
  const crc          = crc32(contentBytes);
  const now          = new Date();
  const dosDate      = ((now.getFullYear()-1980)<<9)|((now.getMonth()+1)<<5)|now.getDate();
  const dosTime      = (now.getHours()<<11)|(now.getMinutes()<<5)|(now.getSeconds()>>1);

  // Local file header
  const localHeader = [
    0x50,0x4B,0x03,0x04,        // signature
    ...u16(20),                  // version needed
    ...u16(0),                   // flags
    ...u16(method),              // compression method (0=store)
    ...u16(dosTime),
    ...u16(dosDate),
    ...u32(crc),
    ...u32(compressed.length),   // compressed size
    ...u32(contentBytes.length), // uncompressed size
    ...u16(nameBytes.length),
    ...u16(0),                   // extra field length
    ...nameBytes,
  ];

  return {
    localHeader,
    data: compressed,
    nameBytes,
    crc,
    method,
    dosTime,
    dosDate,
    compressedSize:   compressed.length,
    uncompressedSize: contentBytes.length,
  };
}

// ── 4f. Build complete ZIP file ──
function buildZip(files) {
  const entries = files.map(([name, content]) => makeZipEntry(name, content));
  const allBytes = [];
  const centralDirInfos = [];
  let offset = 0;

  // Local entries
  for (const e of entries) {
    centralDirInfos.push({ entry: e, offset });
    for (const b of e.localHeader) allBytes.push(b);
    for (const b of e.data)        allBytes.push(b);
    offset += e.localHeader.length + e.data.length;
  }

  // Central directory
  const centralStart = offset;
  for (const { entry: e, offset: localOffset } of centralDirInfos) {
    const cd = [
      0x50,0x4B,0x01,0x02,        // signature
      ...u16(20),                  // version made by
      ...u16(20),                  // version needed
      ...u16(0),                   // flags
      ...u16(e.method),
      ...u16(e.dosTime),
      ...u16(e.dosDate),
      ...u32(e.crc),
      ...u32(e.compressedSize),
      ...u32(e.uncompressedSize),
      ...u16(e.nameBytes.length),
      ...u16(0),                   // extra
      ...u16(0),                   // comment
      ...u16(0),                   // disk start
      ...u16(0),                   // internal attr
      ...u32(0),                   // external attr
      ...u32(localOffset),
      ...e.nameBytes,
    ];
    for (const b of cd) allBytes.push(b);
    offset += cd.length;
  }

  // End of central directory
  const centralSize = offset - centralStart;
  const eocd = [
    0x50,0x4B,0x05,0x06,
    ...u16(0), ...u16(0),
    ...u16(entries.length),
    ...u16(entries.length),
    ...u32(centralSize),
    ...u32(centralStart),
    ...u16(0),
  ];
  for (const b of eocd) allBytes.push(b);

  return allBytes;
}

// ── 4g. Convert byte array → Base64 (pure JS) ──
function bytesToBase64(bytes) {
  const chars = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/';
  let result = '';
  let i = 0;
  while (i < bytes.length) {
    const b0 = bytes[i++] || 0;
    const b1 = bytes[i++];
    const b2 = bytes[i++];
    result += chars[b0 >> 2];
    result += chars[((b0 & 3) << 4) | ((b1 ?? 0) >> 4)];
    result += b1 !== undefined ? chars[((b1 & 15) << 2) | ((b2 ?? 0) >> 6)] : '=';
    result += b2 !== undefined ? chars[b2 & 63] : '=';
  }
  return result;
}

// ── 5. BUILD XLSX XML ─────────────────────────────────────────
function xmlEsc(v) {
  return String(v ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

// Shared strings table
const ssArr = [], ssMap = {};
function ss(val) {
  const s = String(val ?? '');
  if (ssMap[s] === undefined) { ssMap[s] = ssArr.length; ssArr.push(s); }
  return ssMap[s];
}

function colLetter(n) {
  let s = '';
  while (n > 0) { s = String.fromCharCode(64 + (n % 26 || 26)) + s; n = Math.floor((n-1) / 26); }
  return s;
}
function ref(r, c) { return colLetter(c) + r; }
function sCell(r, c, val, si=0) { return `<c r="${ref(r,c)}" t="s" s="${si}"><v>${ss(val)}</v></c>`; }
function nCell(r, c, val, si=0) { return `<c r="${ref(r,c)}" s="${si}"><v>${parseFloat(val)||0}</v></c>`; }

// Style indices:
// 0=normal, 1=header(navy bg white bold), 2=title(large), 3=amount,
// 4=alt row, 5=total, 6=success, 7=failure, 8=kv-label, 9=kv-value-num

function buildSheet1() {
  const rows = []; let r = 1;
  rows.push(`<row r="${r}">${sCell(r,1,'KOTAK MAHINDRA BANK — COMPLETED TRANSFERS STATEMENT',2)}</row>`); r++;
  rows.push(`<row r="${r}">${sCell(r,1,`Account: 4611940519  |  Period: ${fmtDate(dateMin)} — ${fmtDate(dateMax)}  |  Transactions: ${transactions.length.toLocaleString()}  |  Total: INR ${fmtNum(totalAmount)}`,1)}</row>`); r++;
  rows.push(`<row r="${r}"></row>`); r++;
  const hdr = ['Date','Beneficiary Name','Transfer Type','Reference / Account No','Transaction ID','Debit Account','Amount (INR)','Status'];
  rows.push(`<row r="${r}">${hdr.map((h,i)=>sCell(r,i+1,h,1)).join('')}</row>`); r++;

  for (let i = 0; i < transactions.length; i++) {
    const t = transactions[i];
    const s = t.status==='Failure' ? 7 : i%2===1 ? 4 : 0;
    const ns = t.status==='Failure' ? 7 : i%2===1 ? 4 : 3;
    const ss2 = t.status==='Success' ? 6 : t.status==='Failure' ? 7 : s;
    rows.push(`<row r="${r}">
      ${sCell(r,1,t.dateStr,s)}${sCell(r,2,t.beneficiary,s)}${sCell(r,3,t.transferType,s)}
      ${sCell(r,4,t.refId,s)}${sCell(r,5,t.txnId,s)}${sCell(r,6,t.debitAccount,s)}
      ${nCell(r,7,t.amount,ns)}${sCell(r,8,t.status,ss2)}
    </row>`); r++;
  }
  rows.push(`<row r="${r}"></row>`); r++;
  const tr = r;
  rows.push(`<row r="${r}">${sCell(r,1,'GRAND TOTAL',5)}${sCell(r,2,'',5)}${sCell(r,3,'',5)}${sCell(r,4,'',5)}${sCell(r,5,'',5)}${sCell(r,6,'',5)}${nCell(r,7,totalAmount,5)}${sCell(r,8,`${successCount} Success / ${failureCount} Failure`,5)}</row>`);

  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">
<sheetViews><sheetView workbookViewId="0"><pane ySplit="4" topLeftCell="A5" activePane="bottomLeft" state="frozen"/></sheetView></sheetViews>
<cols><col min="1" max="1" width="14" customWidth="1"/><col min="2" max="2" width="32" customWidth="1"/><col min="3" max="3" width="22" customWidth="1"/><col min="4" max="4" width="24" customWidth="1"/><col min="5" max="5" width="15" customWidth="1"/><col min="6" max="6" width="16" customWidth="1"/><col min="7" max="7" width="18" customWidth="1"/><col min="8" max="8" width="14" customWidth="1"/></cols>
<sheetData>${rows.join('')}</sheetData>
<mergeCells count="3"><mergeCell ref="A1:H1"/><mergeCell ref="A2:H2"/><mergeCell ref="A${tr}:F${tr}"/></mergeCells>
</worksheet>`;
}

function buildSheet2() {
  const rows = []; let r = 1;
  const R = (cells) => { rows.push(`<row r="${r}">${cells}</row>`); r++; };
  const E = () => { rows.push(`<row r="${r}"></row>`); r++; };

  R(sCell(r,1,'BANK STATEMENT SUMMARY — KOTAK MAHINDRA BANK',2));
  E();
  R(sCell(r,1,'ACCOUNT OVERVIEW',1));
  R(sCell(r,1,'Account Number',8)+sCell(r,2,'4611940519',0));
  R(sCell(r,1,'Bank Name',8)+sCell(r,2,'Kotak Mahindra Bank',0));
  R(sCell(r,1,'Statement Period',8)+sCell(r,2,`${fmtDate(dateMin)} to ${fmtDate(dateMax)}`,0));
  R(sCell(r,1,'Total Transactions',8)+nCell(r,2,transactions.length,9));
  R(sCell(r,1,'Successful',8)+nCell(r,2,successCount,9));
  R(sCell(r,1,'Failed',8)+nCell(r,2,failureCount,9));
  E();
  R(sCell(r,1,'FINANCIAL SUMMARY',1));
  R(sCell(r,1,'Total Amount Debited (INR)',8)+nCell(r,2,totalAmount,9));
  R(sCell(r,1,'Average Transaction (INR)',8)+nCell(r,2,totalAmount/transactions.length,9));
  R(sCell(r,1,'Largest Transaction (INR)',8)+nCell(r,2,Math.max(...transactions.map(t=>t.amount)),9));
  R(sCell(r,1,'Smallest Transaction (INR)',8)+nCell(r,2,Math.min(...transactions.filter(t=>t.amount>0).map(t=>t.amount)),9));
  E();
  R(sCell(r,1,'BY TRANSFER TYPE',1)+sCell(r,2,'',1)+sCell(r,3,'',1));
  R(sCell(r,1,'Transfer Type',1)+sCell(r,2,'Count',1)+sCell(r,3,'Total Amount (INR)',1));
  for(const [k,v] of Object.entries(typeMap).sort((a,b)=>b[1].total-a[1].total)){
    R(sCell(r,1,k,8)+nCell(r,2,v.count,0)+nCell(r,3,v.total,9));
  }
  E();
  R(sCell(r,1,'TOP 10 BENEFICIARIES',1)+sCell(r,2,'',1)+sCell(r,3,'',1));
  R(sCell(r,1,'Beneficiary Name',1)+sCell(r,2,'Total Amount (INR)',1)+sCell(r,3,'Transactions',1));
  for(const [name,v] of top10){
    R(sCell(r,1,name,8)+nCell(r,2,v.total,9)+nCell(r,3,v.count,0));
  }

  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">
<cols><col min="1" max="1" width="36" customWidth="1"/><col min="2" max="2" width="24" customWidth="1"/><col min="3" max="3" width="22" customWidth="1"/></cols>
<sheetData>${rows.join('')}</sheetData>
<mergeCells count="1"><mergeCell ref="A1:C1"/></mergeCells>
</worksheet>`;
}

function buildSheet3() {
  const rows = []; let r = 1;
  rows.push(`<row r="${r}">${sCell(r,1,'MONTHLY TRANSACTION ANALYSIS',2)}</row>`); r++;
  rows.push(`<row r="${r}"></row>`); r++;
  rows.push(`<row r="${r}">${['Month','No. of Transactions','Total Amount (INR)','Avg Amount (INR)','Success Rate'].map((h,i)=>sCell(r,i+1,h,1)).join('')}</row>`); r++;

  const sorted = Object.entries(monthlyMap).sort((a,b)=>b[0].localeCompare(a[0]));
  for(let i=0;i<sorted.length;i++){
    const [month,v] = sorted[i];
    const s = i%2===1 ? 4 : 0;
    const sr = ((v.success/v.count)*100).toFixed(1)+'%';
    rows.push(`<row r="${r}">${sCell(r,1,month,s)}${nCell(r,2,v.count,s)}${nCell(r,3,v.total,3)}${nCell(r,4,v.total/v.count,3)}${sCell(r,5,sr,s)}</row>`); r++;
  }
  rows.push(`<row r="${r}"></row>`); r++;
  const totC = Object.values(monthlyMap).reduce((s,v)=>s+v.count,0);
  const totT = Object.values(monthlyMap).reduce((s,v)=>s+v.total,0);
  rows.push(`<row r="${r}">${sCell(r,1,'GRAND TOTAL',5)}${nCell(r,2,totC,5)}${nCell(r,3,totT,5)}${sCell(r,4,'',5)}${sCell(r,5,'',5)}</row>`);

  return `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">
<sheetViews><sheetView workbookViewId="0"><pane ySplit="3" topLeftCell="A4" activePane="bottomLeft" state="frozen"/></sheetView></sheetViews>
<cols><col min="1" max="1" width="16" customWidth="1"/><col min="2" max="2" width="20" customWidth="1"/><col min="3" max="3" width="22" customWidth="1"/><col min="4" max="4" width="22" customWidth="1"/><col min="5" max="5" width="16" customWidth="1"/></cols>
<sheetData>${rows.join('')}</sheetData>
<mergeCells count="1"><mergeCell ref="A1:E1"/></mergeCells>
</worksheet>`;
}

// Build all sheets first (populates ssArr)
const sheet1Xml = buildSheet1();
const sheet2Xml = buildSheet2();
const sheet3Xml = buildSheet3();

// Shared strings (built after sheets so all strings are collected)
const sharedStringsXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" count="${ssArr.length}" uniqueCount="${ssArr.length}">
${ssArr.map(s=>`<si><t xml:space="preserve">${xmlEsc(s)}</t></si>`).join('')}
</sst>`;

const stylesXml = `<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<styleSheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">
<fonts count="6">
  <font><sz val="10"/><name val="Arial"/></font>
  <font><b/><sz val="10"/><color rgb="FFFFFFFF"/><name val="Arial"/></font>
  <font><b/><sz val="13"/><color rgb="FFFFFFFF"/><name val="Arial"/></font>
  <font><b/><sz val="10"/><color rgb="FF1B7F4A"/><name val="Arial"/></font>
  <font><b/><sz val="10"/><color rgb="FFCC0000"/><name val="Arial"/></font>
  <font><b/><sz val="10"/><color rgb="FF1B3A6B"/><name val="Arial"/></font>
</fonts>
<fills count="6">
  <fill><patternFill patternType="none"/></fill>
  <fill><patternFill patternType="gray125"/></fill>
  <fill><patternFill patternType="solid"><fgColor rgb="FF1B3A6B"/></patternFill></fill>
  <fill><patternFill patternType="solid"><fgColor rgb="FFEEF4FF"/></patternFill></fill>
  <fill><patternFill patternType="solid"><fgColor rgb="FFFFEBEE"/></patternFill></fill>
  <fill><patternFill patternType="solid"><fgColor rgb="FF2C4F8A"/></patternFill></fill>
</fills>
<borders count="2">
  <border><left/><right/><top/><bottom/><diagonal/></border>
  <border><left style="thin"><color rgb="FFC5CAE9"/></left><right style="thin"><color rgb="FFC5CAE9"/></right><top style="thin"><color rgb="FFC5CAE9"/></top><bottom style="thin"><color rgb="FFC5CAE9"/></bottom></border>
</borders>
<cellStyleXfs count="1"><xf numFmtId="0" fontId="0" fillId="0" borderId="0"/></cellStyleXfs>
<cellXfs count="10">
  <xf numFmtId="0"  fontId="0" fillId="0" borderId="1" xfId="0"><alignment vertical="center"/></xf>
